      "all_three_are_mandatory_goggles_protec": "Ĉiuj tri estas devigaj: la okulvitroj protektas la okulojn kontraŭ ŝprucoj, la gantoj protektas la manojn kontraŭ korodaĵoj, kaj la kitelo protektas vestaĵojn kaj haŭton.",
      "rinse_with_running_water_for_15_min": "Skolu per fluanta akvo dum 15+ min",
      "water_first_always_the_15_minute_rinse": "Akvo unue, ĉiam! La 15-minuta skolado estas esenca. Neŭtraligiloj povas kaŭzi eksotermajn reakciojn sur la haŭto.",
      "where_moles_of_acid_moles_of_base": "Kie moloj de acido = moloj de bazo",
      "the_equivalence_point_is_the_stoichiom": "La ekvivalenta punkto estas la stoiĥiometria punkto. La pH ĉe ekvivalento dependas de la acida/baza forto — ĝi estas pH 7 nur por forta acido + forta bazo.",
      "the_exothermic_reaction_can_cause_viol": "La eksoterma reakcio povas kaŭzi perfortan bolon kaj ŝprucojn",
      "when_water_hits_concentrated_acid_the_": "Kiam akvo trafas koncentritan acidon, la liberigita varmo povas tuj boligi la akvon, kaŭzante perfortan ŝprucon de varma acido. Aldoni acidon al akvo disvastigas la varmon tra pli granda volumo da akvo.",
      "above_7": "Super 7",
      "at_equivalence_only_the_conjugate_base": "Ĉe ekvivalento, nur la konjugita bazo (A⁻) restas. La konjugitaj bazoj de malfortaj acidoj estas mem malfortaj bazoj, farante la solvaĵon baza (pH > 7).",
      "strong_acid_strong_base_or_weak_acid_s": "Forta acido + Forta bazo aŭ Malforta acido + Forta bazo",
      "phenolphthalein_transitions_at_ph_8_2_": "Fenolftaleino transiras je pH 8,2-10,0, kio kongruas kun la baza ekvivalenta pH de titradoj de malforta acido + forta bazo. Ĝi ankaŭ funkcias por FA+FB ĉar la akra salto trairas ĝian gamon.",
      "ammonia_or_acids": "Amoniako aŭ acidoj",
      "bleach_ammonia_chloramine_gas_toxic_bl": "Blankigilo + amoniako = kloramina gaso (toksa). Blankigilo + acido = klora gaso (toksa). Ambaŭ povas kaŭzi gravan spirvojan vundon aŭ morton. NENIAM kombinu blankigilon kun ajna kemiaĵo.",
      "23_45_has_4_significant_figures_the_la": "23,45 havas 4 signifajn ciferojn. La lasta cifero (5) estas taksita inter la gradaĵoj. Buretoj estas precizaj ĝis ±0,05 mL.",
      "ph_pka": "pH = pKa",
      "at_half_equivalence_ha_a_so_henderson_": "Ĉe duonekvivalento, [HA] = [A⁻], do Henderson–Hasselbalch donas pH = pKa + log(1) = pKa. Tio estas la centro de la bufra regiono.",
      "when_handling_1m_concentrated_acids_or": "Kiam oni manipulas koncentritajn acidojn aŭ bazojn >1 M",
      "face_shields_provide_splash_protection": "Vizaĝŝildoj provizas ŝprucprotekton por la tuta vizaĝo. Postulataj por koncentritaj (>1 M) korodaĵoj, hejtaj operacioj, kaj ajna proceduro kun ŝpruca risko preter la okula areo.",
