      "critical_rest_stop_after_the_500_mile_": "Kritika ripozhalto post la 500-mejla transiro de la Meksika Golfo",
      "platte_river_ne": "Platte River, NE",
      "600_000_sandhill_cranes_gather_here_ea": "600 000 Sandhill Cranes kunvenas ĉi tie ĉiu-printempe — unu el la plej grandaj spektakloj de la naturo",
      "great_salt_lake": "Great Salt Lake",
      "5_million_migratory_birds_depend_on_th": "5 milionoj da migraj birdoj dependas de ĉi tiu enlanda maro kiel retankiga stacio",
      "mississippi_delta": "Misisipa Delto",
      "wetlands_here_support_40_of_north_amer": "La marĉejoj ĉi tie subtenas 40 % de la nord-amerikaj migraj akvobirdoj",
      "chesapeake_bay": "Chesapeake Bay",
      "largest_estuary_in_the_us_critical_win": "La plej granda estuaro en Usono — kritika vintra vivejo por anasoj kaj anseroj",
      "atlantic": "Atlantika",
      "mississippi": "Misisipa",
