      "trace_the_journey_of_a_breath_of_air_f": "Sekvu la vojaĝon de spiro da aero de la nazo al la alveoloj kaj reen.",
      "nasal_cavity_2": "Naza kavo",
      "air_enters_through_the_nostrils_and_is": "La aero eniras tra la naztruoj kaj estas varmigata, humidigata kaj filtrata de mukmembranoj kaj nazkonkoj.",
      "pharynx_2": "Faringo",
      "air_passes_through_the_nasopharynx_and": "La aero pasas tra la nazofaringo kaj la orofaringo, trairejo dividata kun la digesta trakto.",
      "larynx": "Laringo",
      "air_crosses_the_vocal_cords_in_the_voi": "La aero transiras la voĉkordojn en la voĉorgano. La epigloto protektas kontraŭ eniro de manĝaĵo en la spirvojon.",
      "trachea_2": "Trakeo",
      "the_trachea_windpipe_is_reinforced_by_": "La trakeo estas plifortigata de C-formaj kartilagaj ringoj. Cilioj movas la mukon supren por kapti partiklojn.",
      "bronchi": "Bronkoj",
      "the_trachea_splits_into_left_and_right": "La trakeo dividiĝas en la maldekstran kaj dekstran ĉefbronkojn, ĉiu enirante unu pulmon. Ili disbranĉiĝas en pli malgrandajn bronkiolojn.",
      "alveoli_2": "Alveoloj",
      "300_million_grape_like_sacs_where_gas_": "300 milionoj da vinberformaj saketoj kie okazas la gasinterŝanĝo. O2 difuzas en la sangon; CO2 difuzas eksteren. La areo egalas al teniskorto.",
      "exhalation": "Elspirado",
      "the_diaphragm_relaxes_and_rises_reduci": "La diafragmo malstreĉiĝas kaj leviĝas, reduktante la pulman volumenon. CO2-riĉa aero estas puŝata eksteren laŭ la sama vojo inverse.",
      "path_of_food": "Vojo de la manĝaĵo",
